class Solution:
    def leastBricks(self, wall):
        from collections import defaultdict
        counts = defaultdict(int)
        best = 0
        for row in wall:
            pos = 0
            for w in row[:-1]:
                pos += w
                counts[pos] += 1
                if counts[pos] > best:
                    best = counts[pos]
        return len(wall) - best

