class Solution:
    def leastBricks(self, wall):
        from collections import Counter
        seams = Counter()
        for row in wall:
            pos = 0
            for w in row[:-1]:
                pos += w
                seams[pos] += 1
        best = max(seams.values()) if seams else 0
        return len(wall) - best

