var leastBricks = function(wall) {
    const seams = new Map();
    let best = 0;
    for (const row of wall) {
        let pos = 0;
        for (let i = 0; i < row.length - 1; i++) {
            pos += row[i];
            const c = (seams.get(pos) || 0) + 1;
            seams.set(pos, c);
            if (c > best) best = c;
        }
    }
    return wall.length - best;
};
